func:
let rows = msg.payload;

if (Array.isArray(rows) && Array.isArray(rows[0])) {
    rows = rows[0];
}

rows = JSON.parse(JSON.stringify(rows || []));

if (!Array.isArray(rows) || rows.length === 0) {
    node.warn("No hay OC pendientes para enviar");
    return null;
}

const nroOc = rows[0].nro_oc;
const mailProveedor = rows[0].mail;

return {
    payload: JSON.stringify({
        api_key: "Corona1234$",
        data: rows
    }),
    headers: {
        "Content-Type": "application/json"
    },
    oc_envio: {
        nro_oc: nroOc,
        mail: mailProveedor,
        total_items: rows.length
    }
};

// Obtener los datos con validacion desde el contexto armado antes del POST
const nro_oc = msg.oc_envio && msg.oc_envio.nro_oc;
const mail = msg.oc_envio && msg.oc_envio.mail;
const httpOk = msg.statusCode >= 200 && msg.statusCode < 300;

if (!nro_oc) {
    node.warn("No se pudo obtener nro_oc, no se actualizara ningun registro");
    return null;
}

if (!httpOk) {
    node.warn(`Webhook n8n respondio status ${msg.statusCode}; OC ${nro_oc} queda pendiente`);
    return null;
}

let estado;
if (mail) {
    estado = 'S';
    node.log(`OC ${nro_oc} tiene mail (${mail}), estado = S`);
} else {
    estado = 'P';
    node.log(`OC ${nro_oc} no tiene mail, estado = P`);
}

msg.topic = `UPDATE ordenes_compra SET enviado = '${estado}', fecha_envio_aut = NOW() WHERE nro_oc = '${nro_oc}'`;
node.log(`Ejecutando: ${msg.topic}`);

return msg;
